module lzc #(parameter WIDTH = 1) (
  input  logic [WIDTH-1:0]            num,
  output logic [$clog2(WIDTH+1)-1:0]  ZeroCnt
);
  integer i;
  always_comb begin
    i = 0;
    while ((i < WIDTH) & ~num[WIDTH-1-i]) i = i+1;
    ZeroCnt = i[$clog2(WIDTH+1)-1:0];
  end
endmodule
